)
RETURNS SETOF __mj."vwReports" AS
$$
BEGIN
IF p_ID IS NOT NULL THEN
        -- User provided a value, use it
        INSERT INTO __mj."Report"
            (
                "ID",
                "Name",
                "Description",
                "CategoryID",
                "UserID",
                "SharingScope",
                "ConversationID",
                "ConversationDetailID",
                "DataContextID",
                "Configuration",
