                "OriginalMessageChanged",
                "AgentSessionID"
            )
        VALUES
            (
                p_ID,
                p_ConversationID,
                CASE WHEN p_ExternalID_Clear = TRUE THEN NULL ELSE COALESCE(p_ExternalID, NULL) END,
