                COALESCE(p_Status, 'Complete'),
                CASE WHEN p_SuggestedResponses_Clear = TRUE THEN NULL ELSE COALESCE(p_SuggestedResponses, NULL) END,
                CASE WHEN p_TestRunID_Clear = TRUE THEN NULL ELSE COALESCE(p_TestRunID, NULL) END,
