CREATE OR REPLACE FUNCTION __mj."spCreateAIAgentSessionBridgeParticipant"(
    IN p_ID UUID DEFAULT NULL,
    IN p_SessionBridgeID UUID DEFAULT NULL,
    IN p_ExternalParticipantID_Clear BOOLEAN DEFAULT FALSE,
    IN p_ExternalParticipantID VARCHAR(500) DEFAULT NULL,
    IN p_DisplayName_Clear BOOLEAN DEFAULT FALSE,
    IN p_DisplayName VARCHAR(500) DEFAULT NULL,
    IN p_Role VARCHAR(20) DEFAULT NULL,
    IN p_UserID_Clear BOOLEAN DEFAULT FALSE,
    IN p_UserID UUID DEFAULT NULL,
    IN p_IsAgent BOOLEAN DEFAULT NULL,
    IN p_JoinedAt_Clear BOOLEAN DEFAULT FALSE,
    IN p_JoinedAt TIMESTAMPTZ DEFAULT NULL,
    IN p_LeftAt_Clear BOOLEAN DEFAULT FALSE,
    IN p_LeftAt TIMESTAMPTZ DEFAULT NULL
)
RETURNS SETOF __mj."vwAIAgentSessionBridgeParticipants" AS
$$
BEGIN
IF p_ID IS NOT NULL THEN
        -- User provided a value, use it
        INSERT INTO __mj."AIAgentSessionBridgeParticipant"
            (
                "ID",
                "SessionBridgeID",
                "ExternalParticipantID",
                "DisplayName",
                "Role",
                "UserID",
                "IsAgent",
                "JoinedAt",
                "LeftAt"
            )
        VALUES
            (
                p_ID,
                p_SessionBridgeID,
                CASE WHEN p_ExternalParticipantID_Clear = TRUE THEN NULL ELSE COALESCE(p_ExternalParticipantID, NULL) END,
                CASE WHEN p_DisplayName_Clear = TRUE THEN NULL ELSE COALESCE(p_DisplayName, NULL) END,
                COALESCE(p_Role, 'Participant'),
                CASE WHEN p_UserID_Clear = TRUE THEN NULL ELSE COALESCE(p_UserID, NULL) END,
                COALESCE(p_IsAgent, FALSE),
                CASE WHEN p_JoinedAt_Clear = TRUE THEN NULL ELSE COALESCE(p_JoinedAt, NULL) END,
                CASE WHEN p_LeftAt_Clear = TRUE THEN NULL ELSE COALESCE(p_LeftAt, NULL) END
            );
    ELSE
        -- No value provided, let database use its default (e.g., gen_random_uuid())
        INSERT INTO __mj."AIAgentSessionBridgeParticipant"
            (
                "SessionBridgeID",
                "ExternalParticipantID",
                "DisplayName",
                "Role",
                "UserID",
                "IsAgent",
                "JoinedAt",
                "LeftAt"
            )
        VALUES
            (
                p_SessionBridgeID,
                CASE WHEN p_ExternalParticipantID_Clear = TRUE THEN NULL ELSE COALESCE(p_ExternalParticipantID, NULL) END,
                CASE WHEN p_DisplayName_Clear = TRUE THEN NULL ELSE COALESCE(p_DisplayName, NULL) END,
                COALESCE(p_Role, 'Participant'),
                CASE WHEN p_UserID_Clear = TRUE THEN NULL ELSE COALESCE(p_UserID, NULL) END,
                COALESCE(p_IsAgent, FALSE),
                CASE WHEN p_JoinedAt_Clear = TRUE THEN NULL ELSE COALESCE(p_JoinedAt, NULL) END,
                CASE WHEN p_LeftAt_Clear = TRUE THEN NULL ELSE COALESCE(p_LeftAt, NULL) END
            );
    END IF;
    -- return the new record from the base view, which might have some calculated fields
    RETURN QUERY SELECT * FROM __mj."vwAIAgentSessionBridgeParticipants" WHERE "ID" = p_ID;
END;
$$ LANGUAGE plpgsql;

